namespace fs = std::filesystem;

// ============================================================================
// RAII Process Handle
// ============================================================================

ProcessHandle::~ProcessHandle() {
    close();
}

void ProcessHandle::close() {
    if (isValid()) {
        CloseHandle(m_handle);
        m_handle = nullptr;
    }
}

ProcessHandle::ProcessHandle(ProcessHandle&& other) noexcept
    : m_handle(other.m_handle) {
    other.m_handle = nullptr;
}

ProcessHandle& ProcessHandle::operator=(ProcessHandle&& other) noexcept {
    if (this != &other) {
        close();
        m_handle = other.m_handle;
        other.m_handle = nullptr;
    }
    return *this;
}

// ============================================================================
// ModelConversionDialog Implementation
// ============================================================================

ModelConversionDialog::ModelConversionDialog(
    const std::vector<std::string>& unsupportedTypes,
    std::string_view recommendedType,
    const fs::path& modelPath,
    HWND parent,
    const ConversionConfig& config
)
    : m_unsupportedTypes(unsupportedTypes)
    , m_recommendedType(recommendedType)
    , m_modelPath(modelPath)
    , m_parent(parent)
    , m_config(config)
{
    // Validate configuration
    if (!m_config.converterPath.empty()) {
        auto validation = validatePaths();
        if (!validation) {
            throw std::invalid_argument(std::format("Invalid configuration: {}", 
                static_cast<int>(validation.error())));
        }
    }
}

ModelConversionDialog::Result ModelConversionDialog::exec() {
    // Step 1: Validate model path (security)
    auto modelValidation = validateModelPath();
    if (!modelValidation) {
        log(std::format("Model path validation failed: {}", 
            static_cast<int>(modelValidation.error())), spdlog::level::err);
        showErrorDialog(std::format("Invalid model path: {}", m_modelPath.string()));
        return Result::Failed;
    }

    // Step 2: Find converter if not specified
    if (m_config.converterPath.empty()) {
        auto converter = findConverter();
        if (!converter) {
            log(std::format("Converter not found: {}", 
                static_cast<int>(converter.error())), spdlog::level::err);
            showErrorDialog(buildConverterNotFoundMessage());
            return Result::Cancelled;
        }
        m_config.converterPath = *converter;
        log(std::format("Found converter: {}", converter->string()), spdlog::level::debug);
    }

    // Step 3: Validate converter
    auto converterValidation = validatePaths();
    if (!converterValidation) {
        log(std::format("Converter validation failed: {}", 
            static_cast<int>(converterValidation.error())), spdlog::level::err);
        showErrorDialog(std::format("Invalid converter: {}", m_config.converterPath.string()));
        return Result::Failed;
    }

    // Step 4: Build user message
    std::string message = buildUserMessage();

    // Step 5: Ask for permission
    if (!askUserPermission(message)) {
        log("User cancelled conversion", spdlog::level::info);
        return Result::Cancelled;
    }

    // Step 6: Build safe command line
    auto commandLine = buildCommandLine();
    if (!commandLine) {
        log(std::format("Failed to build command line: {}", 
            static_cast<int>(commandLine.error())), spdlog::level::err);
        showErrorDialog("Failed to build conversion command.");
        return Result::Failed;
    }

    log(std::format("Starting conversion: {}", *commandLine), spdlog::level::info);
    
    // Step 7: Execute converter
    auto process = executeConverter(*commandLine);
    if (!process) {
        log(std::format("Failed to execute converter: {}", 
            static_cast<int>(process.error())), spdlog::level::err);
        showErrorDialog(std::format("Failed to start converter: {}", 
            static_cast<int>(process.error())));
        return Result::Failed;
    }

    m_processHandle = std::move(*process);
    
    // Step 8: Monitor process
    monitorProcess(m_processHandle, m_config.timeout);
    
    // Step 9: Handle result
    return handleConversionResult();
}

void ModelConversionDialog::execAsync(
    std::function<void(Result, const ConversionResult&)> callback
) {
    // Run in background thread
    std::thread([this, callback]() {
        Result result = exec();
        callback(result, m_conversionResult);
    }).detach();
}

// ============================================================================
// Validation & Security
// ============================================================================

std::expected<void, ConversionError> ModelConversionDialog::validatePaths() const {
    if (m_config.converterPath.empty()) {
        return std::unexpected(ConversionError::ConverterNotFound);
    }
    
    if (!fs::exists(m_config.converterPath)) {
        return std::unexpected(ConversionError::ConverterNotFound);
    }
    
    if (!fs::is_regular_file(m_config.converterPath)) {
        return std::unexpected(ConversionError::InvalidConverterPath);
    }
    
    // Check execute permissions
    auto ext = m_config.converterPath.extension().string();
    std::transform(ext.begin(), ext.end(), ext.begin(), ::tolower);
    
    static const std::vector<std::string> validExtensions = {".exe", ".bat", ".cmd", ".com"};
    if (std::find(validExtensions.begin(), validExtensions.end(), ext) == validExtensions.end()) {
        return std::unexpected(ConversionError::InvalidConverterPath);
    }
    
    return {};
}

std::expected<void, ConversionError> ModelConversionDialog::validateModelPath() const {
    // Prevent path traversal
    auto canonicalModel = fs::weakly_canonical(m_modelPath);
    auto canonicalBase = fs::weakly_canonical(m_config.modelsDirectory);
    
    if (!canonicalModel.string().starts_with(canonicalBase.string())) {
        return std::unexpected(ConversionError::PathTraversalDetected);
    }
    
    if (!fs::exists(m_modelPath)) {
        return std::unexpected(ConversionError::InvalidModelPath);
    }
    
    if (!fs::is_regular_file(m_modelPath)) {
        return std::unexpected(ConversionError::InvalidModelPath);
    }
    
    // Validate extension
    auto ext = m_modelPath.extension().string();
    std::transform(ext.begin(), ext.end(), ext.begin(), ::tolower);
    
    if (std::find(m_config.allowedExtensions.begin(), 
                  m_config.allowedExtensions.end(), 
                  ext) == m_config.allowedExtensions.end()) {
        return std::unexpected(ConversionError::InvalidModelPath);
    }
    
    return {};
}

// ============================================================================
// Command Building
// ============================================================================

std::string ModelConversionDialog::buildUserMessage() const {
    std::string message = std::format(
        "The model '{}' uses unsupported quantization types:\n\n", 
        m_modelPath.filename().string()
    );
    
    for (const auto& type : m_unsupportedTypes) {
        message += std::format("  • {}\n", type);
    }
    
    message += std::format("\nRecommended format: {}\n", m_recommendedType);
    message += std::format("\nConverter: {}\n", m_config.converterPath.filename().string());
    message += std::format("Output directory: {}\n", m_modelPath.parent_path().string());
    
    return message;
}

std::string ModelConversionDialog::buildConverterNotFoundMessage() const {
    return std::format(
        "No converter tool found. Please install the conversion utility.\n\n"
        "Unsupported types: {}\n"
        "Recommended: {}\n\n"
        "Searched locations:\n"
        "  • Current directory\n"
        "  • Program Files\\GGUF\n"
        "  • {}", 
        [this]() {
            std::string types;
            for (const auto& t : m_unsupportedTypes) {
                types += t + ", ";
            }
            if (!types.empty()) types.pop_back(), types.pop_back();
            return types;
        }(),
        m_recommendedType,
        m_config.converterPath.empty() ? "Not specified" : m_config.converterPath.string()
    );
}

std::expected<std::string, ConversionError> ModelConversionDialog::buildCommandLine() const {
    // Properly quote paths to prevent command injection
    auto quote = [](const std::string& s) -> std::string {
        return "\"" + s + "\"";
    };
    
    std::string quotedModelPath = quote(m_modelPath.string());
    std::string quotedOutputPath = quote(m_modelPath.parent_path().string());
    std::string quotedConverter = quote(m_config.converterPath.string());
    
    // Build command line with parameters
    std::string commandLine = std::format(
        "{} --input {} --output {} --format {} --types {}",
        quotedConverter,
        quotedModelPath,
        quotedOutputPath,
        m_recommendedType,
        [this]() {
            std::string types;
            for (const auto& t : m_unsupportedTypes) {
                types += t + ",";
            }
            if (!types.empty()) types.pop_back();
            return types;
        }()
    );
    
    // Add optional parameters
    if (m_config.apiKey) {
        commandLine += std::format(" --api-key {}", quote(*m_config.apiKey));
    }
    
    if (m_config.logFile) {
        commandLine += std::format(" --log {}", quote(m_config.logFile->string()));
    }
    
    // Add timeout
    commandLine += std::format(" --timeout {}", m_config.timeout.count());
    
    return commandLine;
}

// ============================================================================
// Process Execution
// ============================================================================

std::expected<ProcessHandle, ConversionError> ModelConversionDialog::executeConverter(
    const std::string& commandLine
) const {
    STARTUPINFOA si = {0};
    si.cb = sizeof(si);
    si.dwFlags = STARTF_USESHOWWINDOW;
    si.wShowWindow = m_config.showUI ? SW_SHOW : SW_HIDE;
    
    PROCESS_INFORMATION pi = {0};
    
    // Create pipe for stdout/stderr redirection
    SECURITY_ATTRIBUTES sa = {0};
    sa.nLength = sizeof(sa);
    sa.bInheritHandle = TRUE;
    
    HANDLE hStdOutRead = nullptr, hStdOutWrite = nullptr;
    if (!CreatePipe(&hStdOutRead, &hStdOutWrite, &sa, 0)) {
        log("Failed to create pipe for stdout", spdlog::level::err);
        return std::unexpected(ConversionError::CommandExecutionFailed);
    }
    
    si.hStdOutput = hStdOutWrite;
    si.hStdError = hStdOutWrite;
    si.dwFlags |= STARTF_USESTDHANDLES;
    
    // Create process
    BOOL success = CreateProcessA(
        nullptr,                           // Application name
        const_cast<LPSTR>(commandLine.c_str()), // Command line
        nullptr,                           // Process attributes
        nullptr,                           // Thread attributes
        TRUE,                              // Inherit handles
        CREATE_NEW_CONSOLE,                // Creation flags
        nullptr,                           // Environment
        nullptr,                           // Current directory
        &si,                               // Startup info
        &pi                                // Process information
    );
    
    // Close unused pipe ends
    CloseHandle(hStdOutWrite);
    
    if (!success) {
        CloseHandle(hStdOutRead);
        DWORD error = GetLastError();
        log(std::format("CreateProcess failed: {}", error), spdlog::level::err);
        return std::unexpected(ConversionError::CommandExecutionFailed);
    }
    
    // Close thread handle (we don't need it)
    CloseHandle(pi.hThread);
    
    // Store stdout handle for reading output
    m_conversionResult.output = readPipeOutput(hStdOutRead);
    CloseHandle(hStdOutRead);
    
    return ProcessHandle(pi.hProcess);
}

std::string ModelConversionDialog::readPipeOutput(HANDLE hPipe) const {
    std::string output;
    char buffer[4096];
    DWORD bytesRead;
    
    while (ReadFile(hPipe, buffer, sizeof(buffer) - 1, &bytesRead, nullptr) && bytesRead > 0) {
        buffer[bytesRead] = '\0';
        output += buffer;
    }
    
    return output;
}

// ============================================================================
// Process Monitoring
// ============================================================================

void ModelConversionDialog::monitorProcess(ProcessHandle& handle, std::chrono::seconds timeout) {
    if (!handle.isValid()) {
        m_conversionResult.success = false;
        m_conversionResult.errorOutput = "Invalid process handle";
        return;
    }
    
    auto start = std::chrono::steady_clock::now();
    DWORD exitCode = STILL_ACTIVE;
    
    while (!m_cancelRequested.load(std::memory_order_relaxed)) {
        // Check if process has exited
        if (!GetExitCodeProcess(handle.get(), &exitCode)) {
            m_conversionResult.success = false;
            m_conversionResult.errorOutput = "Failed to get exit code";
            break;
        }
        
        if (exitCode != STILL_ACTIVE) {
            // Process finished
            m_conversionResult.exitCode = static_cast<int>(exitCode);
            m_conversionResult.success = (exitCode == 0);
            m_conversionResult.duration = std::chrono::duration_cast<std::chrono::milliseconds>(
                std::chrono::steady_clock::now() - start);
            
            // Generate output path
            m_conversionResult.convertedModelPath = m_modelPath.parent_path() / 
                std::format("{}_converted{}", 
                    m_modelPath.stem().string(), 
                    m_modelPath.extension().string());
            
            break;
        }
        
        // Check timeout
        auto elapsed = std::chrono::steady_clock::now() - start;
        if (elapsed > timeout) {
            log("Conversion timed out", spdlog::level::warn);
            TerminateProcess(handle.get(), 1);
            m_conversionResult.success = false;
            m_conversionResult.errorOutput = "Conversion timed out";
            m_conversionResult.duration = std::chrono::duration_cast<std::chrono::milliseconds>(elapsed);
            break;
        }
        
        // Pump messages to keep UI responsive
        if (m_config.showUI && m_parent) {
            MSG msg;
            while (PeekMessage(&msg, nullptr, 0, 0, PM_REMOVE)) {
                TranslateMessage(&msg);
                DispatchMessage(&msg);
            }
        }
        
        std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }
    
    if (m_cancelRequested.load(std::memory_order_relaxed)) {
        TerminateProcess(handle.get(), 1);
        m_conversionResult.success = false;
        m_conversionResult.errorOutput = "Conversion cancelled by user";
        m_conversionResult.duration = std::chrono::duration_cast<std::chrono::milliseconds>(
            std::chrono::steady_clock::now() - start);
    }
}

// ============================================================================
// Result Handling
// ============================================================================

ModelConversionDialog::Result ModelConversionDialog::handleConversionResult() {
    if (m_conversionResult.success) {
        log(std::format("Conversion completed successfully: {}", 
            m_conversionResult.convertedModelPath.string()), spdlog::level::info);
        showInfoDialog(std::format(
            "Conversion completed successfully!\n\n"
            "Output: {}\n"
            "Duration: {} ms\n"
            "Exit Code: {}\n\n"
            "The converted model is ready to use.",
            m_conversionResult.convertedModelPath.filename().string(),
            m_conversionResult.duration.count(),
            m_conversionResult.exitCode.value_or(0)
        ));
        return Result::Converted;
    } else {
        log(std::format("Conversion failed: {}", m_conversionResult.errorOutput), 
            spdlog::level::err);
        showErrorDialog(std::format(
            "Conversion failed!\n\n"
            "Exit Code: {}\n"
            "Error: {}\n\n"
            "Please check the logs for more details.",
            m_conversionResult.exitCode.value_or(-1),
            m_conversionResult.errorOutput.empty() ? "Unknown error" : m_conversionResult.errorOutput
        ));
        return Result::Failed;
    }
}

// ============================================================================
// UI Helpers
// ============================================================================

void ModelConversionDialog::showInfoDialog(const std::string& message) const {
    if (m_config.showUI && m_parent) {
        MessageBoxA(m_parent, message.c_str(), "Model Conversion", MB_OK | MB_ICONINFORMATION);
    }
}

void ModelConversionDialog::showErrorDialog(const std::string& message) const {
    if (m_config.showUI && m_parent) {
        MessageBoxA(m_parent, message.c_str(), "Model Conversion Error", MB_OK | MB_ICONERROR);
    }
}

[[nodiscard]] bool ModelConversionDialog::askUserPermission(const std::string& message) const {
    if (!m_config.showUI) {
        return true; // Non-interactive mode assumes approval
    }
    
    return MessageBoxA(m_parent, message.c_str(), "Model Conversion", 
                      MB_YESNO | MB_ICONQUESTION | MB_DEFBUTTON2) == IDYES;
}

// ============================================================================
// Logging
// ============================================================================

void ModelConversionDialog::log(const std::string& message, spdlog::level::level_enum level) const {
    // Log to file if configured
    if (m_config.logFile) {
        std::ofstream log(*m_config.logFile, std::ios::app);
        if (log) {
            auto now = std::chrono::system_clock::now();
            auto time_t = std::chrono::system_clock::to_time_t(now);
            log << std::format("[{:%Y-%m-%d %H:%M:%S}] {}\n", 
                *std::localtime(&time_t), message);
        }
    }
    
    // Log to spdlog
    spdlog::log(level, "[ModelConversion] {}", message);
}

// ============================================================================
// Static Utilities
// ============================================================================

[[nodiscard]] bool ModelConversionDialog::needsConversion(const fs::path& modelPath) {
    // Check file signature or extension
    auto ext = modelPath.extension().string();
    std::transform(ext.begin(), ext.end(), ext.begin(), ::tolower);
    
    static const std::vector<std::string> unsupported = {".gguf.v1", ".gguf.legacy", ".gguf.old"};
    return std::find(unsupported.begin(), unsupported.end(), ext) != unsupported.end();
}

[[nodiscard]] std::expected<fs::path, ConversionError> ModelConversionDialog::findConverter(
    const fs::path& searchRoot
) {
    spdlog::debug("Searching for converter in: {}", searchRoot.string());
    
    // Common installation locations
    std::vector<fs::path> searchPaths = {
        searchRoot / "bin" / "converter.exe",
        searchRoot / "tools" / "converter.exe",
        searchRoot / "converter.exe",
        fs::current_path() / "converter.exe",
        fs::path(std::getenv("PROGRAMFILES")) / "GGUF" / "converter.exe",
        fs::path(std::getenv("LOCALAPPDATA")) / "GGUF" / "converter.exe"
    };
    
    // Add PATH environment variable locations
    if (const char* pathEnv = std::getenv("PATH")) {
        std::string pathStr(pathEnv);
        size_t start = 0;
        size_t end = pathStr.find(';');
        
        while (end != std::string::npos) {
            fs::path path = pathStr.substr(start, end - start);
            searchPaths.push_back(path / "converter.exe");
            start = end + 1;
            end = pathStr.find(';', start);
        }
        searchPaths.push_back(pathStr.substr(start) / "converter.exe");
    }
    
    // Search for converter
    for (const auto& path : searchPaths) {
        if (fs::exists(path) && fs::is_regular_file(path)) {
            spdlog::info("Found converter at: {}", path.string());
            return path;
        }
    }
    
    spdlog::warn("Converter not found in any standard location");
    return std::unexpected(ConversionError::ConverterNotFound);
}
